#!/usr/bin/env bash
# notes.sh — append-only notes. Usage: notes.sh add <text> | notes.sh list
case "${1:-}" in
  add) shift; echo "$*" >> notes.txt ;;
  list) nl -ba notes.txt 2>/dev/null ;;
  *) echo "usage: notes.sh add <text> | notes.sh list" >&2; exit 2 ;;
esac
